configuration.jsScript:
function nextRelation(metadata, msg) {
    var out_list = [];
    switch (msg.method) {
        case "createRule":
        case "editRule":
            out_list = ['createRule_editRule']
            break;

        case "actionRule":
            out_list = ['actionRule']
            break;

        case "activeRule":    
            out_list = ['activeRule']
            break;

        case "delRule":
            out_list = ['delRule']
            break;

        default:
            out_list = ['other']
            break;
    }
    return out_list;
}
return nextRelation(metadata, msg);

