function convertMessage(input) {
    var result = [];
    var index = 0;

    for (var i = 0; i < input.length; i++) {
        var item = input[i];

        // xác định đây có phải bản tin điều khiển không
        if (item.devId || item.groupId || item.sceneId) {

            var obj = {};

            // copy id
            if (item.devId) {
                obj.devId = item.devId;
            } else if (item.groupId) {
                obj.groupId = item.groupId;
            } else if (item.sceneId) {
                obj.sceneId = item.sceneId;
            }

            // copy data nếu có
            if (item.data) {
                obj.data = item.data;
            }

            // mặc định delay = 0
            obj.delay = 0;

            // nếu phần tử kế tiếp là delay thì gán
            if (input[i + 1] && typeof input[i + 1].delay === "number") {
                obj.delay = input[i + 1].delay;
                i++; // skip object delay
            }

            obj.index = index;
            index++;

            result.push(obj);
        }
    }
    return result;
}

msg = convertMessage(msg.params.output)
return { msg: msg, metadata: metadata, msgType: msgType };

