function findUnusedEntities(input) {
    var usedMap = {};
    var result = [];

    var params = input.params || {};

    //  1. thu thập entity từ params.input.device
    if (params.input && params.input.device) {
        for (var i = 0; i < params.input.device.length; i++) {
            var dev = params.input.device[i];
            if (dev.id) {
                usedMap[dev.id] = true;
            }
        }
    }

    //  2. thu thập entity từ params.output
    if (params.output) {
        for (var j = 0; j < params.output.length; j++) {
            var out = params.output[j];

            if (out.devId) {
                usedMap[out.devId] = true;
            } else if (out.groupId) {
                usedMap[out.groupId] = true;
            } else if (out.sceneId) {
                usedMap[out.sceneId] = true;
            }
        }
    }

    //  3. lọc dataResponse
    if (input.dataResponse) {
        for (var k = 0; k < input.dataResponse.length; k++) {
            var entity = input.dataResponse[k];

            if (!usedMap[entity.entityName]) {
                result.push(entity);
            }
        }
    }

    return result;
}
